// Generated by generate.ts — hidden adversarial suite for clamp.
// Run via `npx tsx __audit__/clamp.hidden.ts` inside the scratch project.
import { clamp, lerp, roundTo } from '../src/clamp'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("clamp in range", clamp(5, 0, 10), 5)
await check("clamp below min", clamp(-5, 0, 10), 0)
await check("clamp above max", clamp(15, 0, 10), 10)
await check("clamp at min", clamp(0, 0, 10), 0)
await check("clamp at max", clamp(10, 0, 10), 10)
await check("lerp halfway", lerp(0, 10, 0.5), 5)
await check("lerp start", lerp(0, 10, 0), 0)
await check("lerp end", lerp(0, 10, 1), 10)
await check("roundTo 2", roundTo(3.14159, 2), 3.14)
await check("roundTo 0", roundTo(3.7, 0), 4)
await check("roundTo 3", roundTo(1.2345, 3), 1.235)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
